import os
from datetime import datetime
from bson import ObjectId
from flask import Flask, request, jsonify
from pymongo import MongoClient, ASCENDING, DESCENDING
from pymongo.errors import DuplicateKeyError

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
DB_NAME = os.getenv("MONGO_DB", "cms")

client = MongoClient(MONGO_URI)
db = client[DB_NAME]

users = db["users"]
documents = db["documents"]

users.create_index([("email", ASCENDING)], unique=True)
users.create_index([("username", ASCENDING)], unique=True)
documents.create_index([("slug", ASCENDING)], unique=True)
documents.create_index([("author_id", ASCENDING), ("created_at", DESCENDING)])
documents.create_index([("status", ASCENDING), ("published_at", DESCENDING)])
documents.create_index([("tags", ASCENDING)])
documents.create_index([("title", "text"), ("body", "text")])


def oid(value):
    try:
        return ObjectId(value)
    except Exception:
        return None


def dt_utcnow():
    return datetime.utcnow()


def to_jsonable(obj):
    if isinstance(obj, ObjectId):
        return str(obj)
    if isinstance(obj, datetime):
        return obj.isoformat() + "Z"
    if isinstance(obj, list):
        return [to_jsonable(x) for x in obj]
    if isinstance(obj, dict):
        return {k: to_jsonable(v) for k, v in obj.items()}
    return obj


def json_response(payload, status=200):
    return jsonify(to_jsonable(payload)), status


def get_pagination_args():
    try:
        limit = int(request.args.get("limit", 20))
    except Exception:
        limit = 20
    try:
        skip = int(request.args.get("skip", 0))
    except Exception:
        skip = 0
    limit = max(1, min(limit, 200))
    skip = max(0, skip)
    return limit, skip


