@app.post("/users")
def create_user():
    data = request.get_json(force=True, silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    username = (data.get("username") or "").strip()
    display_name = (data.get("display_name") or "").strip()
    bio = (data.get("bio") or "").strip()
    roles = data.get("roles") or ["author"]
    if not isinstance(roles, list):
        roles = ["author"]

    if not email or not username:
        return json_response({"error": "email and username are required"}, 400)

    doc = {
        "email": email,
        "username": username,
        "display_name": display_name or username,
        "bio": bio,
        "roles": roles,
        "created_at": dt_utcnow(),
        "updated_at": dt_utcnow(),
    }

    try:
        res = users.insert_one(doc)
    except DuplicateKeyError:
        return json_response({"error": "email or username already exists"}, 409)

    created = users.find_one({"_id": res.inserted_id}, {"_id": 1, "email": 1, "username": 1, "display_name": 1, "bio": 1, "roles": 1, "created_at": 1, "updated_at": 1})
    return json_response(created, 201)


@app.get("/users/<user_id>")
def get_user(user_id):
    _id = oid(user_id)
    if not _id:
        return json_response({"error": "invalid user_id"}, 400)
    doc = users.find_one({"_id": _id}, {"email": 1, "username": 1, "display_name": 1, "bio": 1, "roles": 1, "created_at": 1, "updated_at": 1})
    if not doc:
        return json_response({"error": "not found"}, 404)
