@app.patch("/users/<user_id>")
def update_user(user_id):
    _id = oid(user_id)
    if not _id:
        return json_response({"error": "invalid user_id"}, 400)

    data = request.get_json(force=True, silent=True) or {}
    update = {}
    for field in ["display_name", "bio", "roles"]:
        if field in data:
            update[field] = data[field]
    if "email" in data:
        update["email"] = (data.get("email") or "").strip().lower()
    if "username" in data:
        update["username"] = (data.get("username") or "").strip()

    if not update:
        return json_response({"error": "no fields to update"}, 400)

    update["updated_at"] = dt_utcnow()

