@app.get("/users")
def list_users():
    q = (request.args.get("q") or "").strip()
    limit, skip = get_pagination_args()

    filt = {}
    if q:
        filt = {"$or": [{"email": {"$regex": q, "$options": "i"}}, {"username": {"$regex": q, "$options": "i"}}, {"display_name": {"$regex": q, "$options": "i"}}]}

    cursor = users.find(filt, {"email": 1, "username": 1, "display_name": 1, "bio": 1, "roles": 1, "created_at": 1, "updated_at": 1}).sort("created_at", DESCENDING).skip(skip).limit(limit)
    total = users.count_documents(filt)
    return json_response({"items": list(cursor), "total": total, "limit": limit, "skip": skip})


