@app.post("/documents")
def create_document():
    data = request.get_json(force=True, silent=True) or {}
    title = (data.get("title") or "").strip()
    slug = (data.get("slug") or "").strip()
    body = data.get("body") or ""
    status = (data.get("status") or "draft").strip().lower()
    tags = data.get("tags") or []
    author_id = data.get("author_id")

    if not title or not slug or not author_id:
        return json_response({"error": "title, slug, and author_id are required"}, 400)

    a_id = oid(author_id)
    if not a_id:
        return json_response({"error": "invalid author_id"}, 400)

    if not users.find_one({"_id": a_id}, {"_id": 1}):
        return json_response({"error": "author not found"}, 404)

    if not isinstance(tags, list):
        tags = []

    now = dt_utcnow()
    published_at = data.get("published_at")
    if status == "published" and not published_at:
        published_at = now

    doc = {
        "title": title,
        "slug": slug,
        "body": body,
        "status": status,
        "tags": tags,
        "author_id": a_id,
        "created_at": now,
        "updated_at": now,
        "published_at": published_at if status == "published" else None,
        "meta": data.get("meta") or {},
    }

    try:
        res = documents.insert_one(doc)
    except DuplicateKeyError:
        return json_response({"error": "slug already exists"}, 409)

    created = documents.find_one({"_id": res.inserted_id})
    return json_response(created, 201)


