@app.get("/documents")
def query_documents():
    limit, skip = get_pagination_args()

    status = (request.args.get("status") or "").strip().lower()
    tag = (request.args.get("tag") or "").strip()
    author_id = (request.args.get("author_id") or "").strip()
    q = (request.args.get("q") or "").strip()
    slug = (request.args.get("slug") or "").strip()

    sort = (request.args.get("sort") or "created_at").strip()
    order = (request.args.get("order") or "desc").strip().lower()

    filt = {}
    if status:
        filt["status"] = status
    if tag:
        filt["tags"] = tag
    if slug:
        filt["slug"] = slug
    if author_id:
        a_id = oid(author_id)
        if not a_id:
            return json_response({"error": "invalid author_id"}, 400)
        filt["author_id"] = a_id

    if q:
        filt["$text"] = {"$search": q}

    sort_field = sort if sort in ("created_at", "updated_at", "published_at", "title") else "created_at"
    sort_dir = DESCENDING if order != "asc" else ASCENDING

    projection = None
    if q:
        projection = {"score": {"$meta": "textScore"}}
        cursor = documents.find(filt, projection).sort([("score", {"$meta": "textScore"}), (sort_field, sort_dir)]).skip(skip).limit(limit)
    else:
        cursor = documents.find(filt).sort(sort_field, sort_dir).skip(skip).limit(limit)

    total = documents.count_documents(filt)
    return json_response({"items": list(cursor), "total": total, "limit": limit, "skip": skip})


