@app.get("/analytics/documents/published_over_time")
def analytics_published_over_time():
    interval = (request.args.get("interval") or "day").strip().lower()
    if interval not in ("day", "month"):
        interval = "day"

    date_expr = {
        "day": {"$dateToString": {"format": "%Y-%m-%d", "date": "$published_at"}},
        "month": {"$dateToString": {"format": "%Y-%m", "date": "$published_at"}},
    }[interval]

    pipeline = [
        {"$match": {"status": "published", "published_at": {"$ne": None}}},
        {"$group": {"_id": date_expr, "count": {"$sum": 1}}},
        {"$sort": {"_id": 1}},
    ]
    res = list(documents.aggregate(pipeline))
    return json_response({"items": res, "interval": interval})


@app.post("/aggregate")
def run_custom_aggregate():
    data = request.get_json(force=True, silent=True) or {}
    collection = (data.get("collection") or "documents").strip()
    pipeline = data.get("pipeline")

    if collection not in ("documents", "users"):
        return json_response({"error": "collection must be 'documents' or 'users'"}, 400)
    if not isinstance(pipeline, list):
        return json_response({"error": "pipeline must be a list"}, 400)

    coll = documents if collection == "documents" else users

    try:
        res = list(coll.aggregate(pipeline))
    except Exception as e:
        return json_response({"error": "aggregation failed", "details": str(e)}, 400)

    return json_response({"items": res})


